188→/**
189→ * Release Service API wrapper
190→ */
191→export const releaseService = {
192→    /**
193→     * List all releases with optional filtering and pagination
194→     *
195→     * @param status Optional status filter (PREPARATION, ALIGNMENT, ACTIVE, ARCHIVED)
196→     * @param page Page number (1-indexed)
197→     * @param pageSize Number of items per page
198→     * @returns Paginated list of releases
199→     */
200→    async list(
201→        status?: string,
202→        page: number = 1,
203→        pageSize: number = 20
204→    ): Promise<PaginatedResponse<Release>> {
205→        const params = new URLSearchParams();
206→        if (status && status !== 'ALL') {
207→            params.append('status', status);
208→        }
209→        params.append('page', page.toString());
210→        params.append('pageSize', pageSize.toString());
211→
212→        const response = await authenticatedFetch(`/api/releases?${params}`);
213→        
214→        if (!response.ok) {
215→            throw new Error(`Failed to list releases: ${response.statusText}`);
216→        }
217→
218→        return response.json();
219→    },
220→
221→    /**
222→     * Get release by ID
223→     *
224→     * @param id Release ID
225→     * @returns Release details
226→     */
227→    async getById(id: number): Promise<Release> {
228→        const response = await authenticatedFetch(`/api/releases/${id}`);
229→        
230→        if (!response.ok) {
231→            if (response.status === 404) {
232→                throw new Error('Release not found');
233→            }
234→            throw new Error(`Failed to get release: ${response.statusText}`);
235→        }
236→
237→        return response.json();
238→    },
239→
240→    /**
241→     * Create a new release
242→     *
243→     * @param data Release creation data
244→     * @returns Created release (with PREPARATION status)
245→     */
246→    async create(data: CreateReleaseRequest): Promise<Release> {
247→        const response = await authenticatedFetch('/api/releases', {
248→            method: 'POST',
249→            headers: {
250→                'Content-Type': 'application/json',
251→            },
252→            body: JSON.stringify(data),
253→        });
254→
255→        if (!response.ok) {
256→            const errorText = await response.text();
257→            throw new Error(errorText || `Failed to create release: ${response.statusText}`);
258→        }
259→
260→        return response.json();
261→    },
262→
263→    /**
264→     * Update release status
265→     *
266→     * @param id Release ID
267→     * @param status New status (ACTIVE only)
268→     * @returns Updated release
269→     */
270→    async updateStatus(id: number, status: 'ACTIVE'): Promise<Release> {
271→        const response = await authenticatedFetch(`/api/releases/${id}/status`, {
272→            method: 'PUT',
273→            headers: {
274→                'Content-Type': 'application/json',
275→            },
276→            body: JSON.stringify({ status }),
277→        });
278→
279→        if (!response.ok) {
280→            throw new Error(`Failed to update release status: ${response.statusText}`);
281→        }
282→
283→        return response.json();
284→    },
285→
286→    /**
287→     * Delete release
288→     *
289→     * @param id Release ID
290→     */
291→    async delete(id: number): Promise<void> {
292→        const response = await authenticatedFetch(`/api/releases/${id}`, {
293→            method: 'DELETE',
294→        });
295→
296→        if (!response.ok) {
297→            if (response.status === 403) {
298→                throw new Error('You do not have permission to delete this release.');
299→            }
300→            throw new Error(`Failed to delete release: ${response.statusText}`);
301→        }
302→    },
303→
304→    /**
305→     * Get requirement snapshots for a release
306→     *
307→     * @param id Release ID
308→     * @param page Page number (1-indexed)
309→     * @param pageSize Number of items per page
310→     * @returns Paginated list of requirement snapshots
311→     */
312→    async getSnapshots(
313→        id: number,
314→        page: number = 1,
315→        pageSize: number = 50
316→    ): Promise<PaginatedResponse<RequirementSnapshot>> {
317→        const params = new URLSearchParams();
318→        params.append('page', page.toString());
319→        params.append('pageSize', pageSize.toString());
320→
321→        const response = await authenticatedFetch(`/api/releases/${id}/requirements?${params}`);
322→        
323→        if (!response.ok) {
324→            throw new Error(`Failed to get release snapshots: ${response.statusText}`);
325→        }
326→
327→        return response.json();
328→    },
329→
330→    /**
331→     * Compare two releases
332→     *
333→     * @param fromReleaseId Source release ID
334→     * @param toReleaseId Target release ID
335→     * @returns Comparison results
336→     */
337→    async compare(fromReleaseId: number, toReleaseId: number): Promise<ReleaseComparison> {
338→        const params = new URLSearchParams();
339→        params.append('fromReleaseId', fromReleaseId.toString());
340→        params.append('toReleaseId', toReleaseId.toString());
341→
342→        const response = await authenticatedFetch(`/api/releases/compare?${params}`);
343→
344→        if (!response.ok) {
345→            throw new Error(`Failed to compare releases: ${response.statusText}`);
346→        }
347→
348→        return response.json();
349→    },
350→
351→    // ========== Feature 185: Requirements Alignment Process ==========
352→
353→    /**
354→     * Check if a release has changes that need alignment review
355→     *
356→     * @param releaseId Release ID
357→     * @returns Whether the release has changes to review
358→     */
359→    async checkAlignmentRequired(releaseId: number): Promise<{ hasChanges: boolean }> {
360→        const response = await authenticatedFetch(`/api/releases/${releaseId}/alignment/check`);
361→
362→        if (!response.ok) {
363→            throw new Error(`Failed to check alignment status: ${response.statusText}`);
364→        }
365→
366→        return response.json();
367→    },
368→
369→    /**
370→     * Start alignment process for a PREPARATION release
371→     *
372→     * @param releaseId Release ID
373→     * @param reviewAll If true, include all requirements (not just changed ones)
374→     * @returns Alignment start result with session details
375→     */
376→    async startAlignment(releaseId: number, reviewAll: boolean = false): Promise<AlignmentStartResult> {
377→        const response = await authenticatedFetch(`/api/releases/${releaseId}/alignment/start`, {
378→            method: 'POST',
379→            headers: {
380→                'Content-Type': 'application/json',
381→            },
382→            body: JSON.stringify({ reviewAll }),
383→        });
384→
385→        if (!response.ok) {
386→            const errorData = await response.json().catch(() => ({}));
387→            throw new Error(errorData.message || `Failed to start alignment: ${response.statusText}`);
388→        }
389→
390→        return response.json();
391→    },
392→
393→    /**
394→     * Get alignment status for a release
395→     *
396→     * @param releaseId Release ID
397→     * @returns Alignment status including reviewer progress
398→     */
399→    async getAlignmentStatus(releaseId: number): Promise<AlignmentStatus> {
400→        const response = await authenticatedFetch(`/api/releases/${releaseId}/alignment`);
401→
402→        if (!response.ok) {
403→            if (response.status === 404) {
404→                throw new Error('No active alignment session for this release');
405→            }
406→            throw new Error(`Failed to get alignment status: ${response.statusText}`);
407→        }
408→
409→        return response.json();
410→    },
411→
412→    /**
413→     * Get alignment session details by session ID
414→     *
415→     * @param sessionId Alignment session ID
416→     * @returns Alignment status
417→     */
418→    async getAlignmentSessionStatus(sessionId: number): Promise<AlignmentStatus> {
419→        const response = await authenticatedFetch(`/api/alignment/${sessionId}`);
420→
421→        if (!response.ok) {
422→            throw new Error(`Failed to get alignment session: ${response.statusText}`);
423→        }
424→
425→        return response.json();
426→    },
427→
428→    /**
429→     * Get alignment snapshots (changed requirements)
430→     *
431→     * @param sessionId Alignment session ID
432→     * @param changeType Optional filter by change type
433→     * @returns List of requirement changes
434→     */
435→    async getAlignmentSnapshots(
436→        sessionId: number,
437→        changeType?: 'ADDED' | 'MODIFIED' | 'DELETED'
438→    ): Promise<{ snapshots: AlignmentSnapshot[]; totalCount: number }> {
439→        const params = new URLSearchParams();
440→        if (changeType) {
441→            params.append('changeType', changeType);
442→        }
443→
444→        const response = await authenticatedFetch(`/api/alignment/${sessionId}/snapshots?${params}`);
445→
446→        if (!response.ok) {
447→            throw new Error(`Failed to get alignment snapshots: ${response.statusText}`);
448→        }
449→
450→        return response.json();
451→    },
452→
453→    /**
454→     * Get reviewer details for an alignment session
455→     *
456→     * @param sessionId Alignment session ID
457→     * @returns List of reviewers with their progress
458→     */
459→    async getAlignmentReviewers(sessionId: number): Promise<{ reviewers: AlignmentReviewer[] }> {
460→        const response = await authenticatedFetch(`/api/alignment/${sessionId}/reviewers`);
461→
462→        if (!response.ok) {
463→            throw new Error(`Failed to get alignment reviewers: ${response.statusText}`);
464→        }
465→
466→        return response.json();
467→    },
468→
469→    /**
470→     * Get aggregated feedback for all requirements
471→     *
472→     * @param sessionId Alignment session ID
473→     * @returns Per-requirement feedback summary
474→     */
475→    async getAlignmentFeedback(sessionId: number): Promise<any> {
476→        const response = await authenticatedFetch(`/api/alignment/${sessionId}/feedback`);
477→
478→        if (!response.ok) {
479→            throw new Error(`Failed to get alignment feedback: ${response.statusText}`);
480→        }
481→
482→        return response.json();
483→    },
484→
485→    /**
486→     * Send reminder emails to incomplete reviewers
487→     *
488→     * @param sessionId Alignment session ID
489→     * @returns Reminder send result
490→     */
491→    async sendAlignmentReminders(sessionId: number): Promise<{ success: boolean; remindersSent: number }> {
492→        const response = await authenticatedFetch(`/api/alignment/${sessionId}/remind`, {
493→            method: 'POST',
494→        });
495→
496→        if (!response.ok) {
497→            throw new Error(`Failed to send reminders: ${response.statusText}`);
498→        }
499→
500→        return response.json();
501→    },
502→
503→    /**
504→     * Finalize alignment and optionally activate release
505→     *
506→     * @param sessionId Alignment session ID
507→     * @param activateRelease Whether to activate the release
508→     * @param notes Optional completion notes
509→     * @returns Finalization result
510→     */
511→    async finalizeAlignment(
512→        sessionId: number,
513→        activateRelease: boolean,
514→        notes?: string
515→    ): Promise<{ success: boolean; message: string; session: AlignmentSession }> {
516→        const response = await authenticatedFetch(`/api/alignment/${sessionId}/finalize`, {
517→            method: 'POST',
518→            headers: {
519→                'Content-Type': 'application/json',
520→            },
521→            body: JSON.stringify({ activateRelease, notes }),
522→        });
523→
524→        if (!response.ok) {
525→            const errorData = await response.json().catch(() => ({}));
526→            throw new Error(errorData.message || `Failed to finalize alignment: ${response.statusText}`);
527→        }
528→
529→        return response.json();
530→    },
531→
532→    /**
533→     * Cancel alignment and return release to PREPARATION
534→     *
535→     * @param sessionId Alignment session ID
536→     * @param notes Optional cancellation notes
537→     * @returns Cancellation result
538→     */
539→    async cancelAlignment(
540→        sessionId: number,
541→        notes?: string
542→    ): Promise<{ success: boolean; message: string; session: AlignmentSession }> {
543→        const response = await authenticatedFetch(`/api/alignment/${sessionId}/cancel`, {
544→            method: 'POST',
545→            headers: {
546→                'Content-Type': 'application/json',
547→            },
548→            body: JSON.stringify({ notes }),
549→        });
550→
551→        if (!response.ok) {
552→            const errorData = await response.json().catch(() => ({}));
553→            throw new Error(errorData.message || `Failed to cancel alignment: ${response.statusText}`);
554→        }
555→
556→        return response.json();
557→    },
558→
559→    /**
560→     * Submit an admin decision (ACCEPTED/REJECTED) on a reviewer's assessment
561→     *
562→     * @param sessionId Alignment session ID
563→     * @param reviewId Review ID
564→     * @param decision ACCEPTED or REJECTED
565→     * @param comment Optional admin comment
566→     * @returns Decision result
567→     */
568→    async submitReviewDecision(
569→        sessionId: number,
570→        reviewId: number,
571→        decision: 'ACCEPTED' | 'REJECTED',
572→        comment?: string
573→    ): Promise<{ success: boolean; message: string }> {
574→        const response = await authenticatedFetch(`/api/alignment/${sessionId}/decisions`, {
575→            method: 'PUT',
576→            headers: {
577→                'Content-Type': 'application/json',
578→            },
579→            body: JSON.stringify({ reviewId, decision, comment }),
580→        });
581→
582→        if (!response.ok) {
583→            const errorData = await response.json().catch(() => ({}));
584→            throw new Error(errorData.message || `Failed to submit decision: ${response.statusText}`);
