  1→/**
  2→ * AlignmentDashboard Component
  3→ *
  4→ * Dashboard for Release Managers to view and manage alignment sessions.
  5→ * Shows reviewer progress, assessment summary, and allows finalization.
  6→ *
  7→ * Feature: 068-requirements-alignment-process
  8→ */
  9→
 10→import React, { useState, useEffect } from 'react';
 11→import {
 12→    releaseService,
 13→    type Release,
 14→    type AlignmentStatus,
 15→    type AlignmentReviewer,
 16→    type AdminDecision,
 17→} from '../services/releaseService';
 18→import { hasRole } from '../utils/auth';
 19→
 20→interface AlignmentDashboardProps {
 21→    releaseId: number;
 22→}
 23→
 24→type TabType = 'overview' | 'reviewers' | 'feedback';
 25→
 26→export const AlignmentDashboard: React.FC<AlignmentDashboardProps> = ({ releaseId }) => {
 27→    const [release, setRelease] = useState<Release | null>(null);
 28→    const [alignmentStatus, setAlignmentStatus] = useState<AlignmentStatus | null>(null);
 29→    const [reviewers, setReviewers] = useState<AlignmentReviewer[]>([]);
 30→    const [feedback, setFeedback] = useState<any[]>([]);
 31→    const [activeTab, setActiveTab] = useState<TabType>('overview');
 32→    const [isLoading, setIsLoading] = useState(true);
 33→    const [error, setError] = useState<string | null>(null);
 34→    const [actionLoading, setActionLoading] = useState<string | null>(null);
 35→
 36→    const canManage = typeof window !== 'undefined' && hasRole(['ADMIN', 'RELEASE_MANAGER']);
 37→    const canDecide = typeof window !== 'undefined' && hasRole(['ADMIN', 'REQADMIN']);
 38→    const [decisionComments, setDecisionComments] = useState<Record<number, string>>({});
 39→    const [decisionLoading, setDecisionLoading] = useState<number | null>(null);
 40→
 41→    // Load data
 42→    useEffect(() => {
 43→        loadData();
 44→    }, [releaseId]);
 45→
 46→    const loadData = async () => {
 47→        setIsLoading(true);
 48→        setError(null);
 49→
 50→        try {
 51→            const [releaseData, statusData] = await Promise.all([
 52→                releaseService.getById(releaseId),
 53→                releaseService.getAlignmentStatus(releaseId),
 54→            ]);
 55→
 56→            setRelease(releaseData);
 57→            setAlignmentStatus(statusData);
 58→
 59→            // Load reviewers if we have a session
 60→            if (statusData.session.id) {
 61→                const reviewerData = await releaseService.getAlignmentReviewers(statusData.session.id);
 62→                setReviewers(reviewerData.reviewers);
 63→
 64→                const feedbackData = await releaseService.getAlignmentFeedback(statusData.session.id);
 65→                setFeedback(feedbackData.requirements || []);
 66→            }
 67→        } catch (err) {
 68→            setError(err instanceof Error ? err.message : 'Failed to load alignment data');
 69→        } finally {
 70→            setIsLoading(false);
 71→        }
 72→    };
 73→
 74→    const handleSendReminders = async () => {
 75→        if (!alignmentStatus?.session.id) return;
 76→
 77→        setActionLoading('remind');
 78→        try {
 79→            const result = await releaseService.sendAlignmentReminders(alignmentStatus.session.id);
 80→            alert(`Sent ${result.remindersSent} reminder(s)`);
 81→            loadData();
 82→        } catch (err) {
 83→            alert(err instanceof Error ? err.message : 'Failed to send reminders');
 84→        } finally {
 85→            setActionLoading(null);
 86→        }
 87→    };
 88→
 89→    const handleFinalize = async (activate: boolean) => {
 90→        if (!alignmentStatus?.session.id) return;
 91→
 92→        const action = activate ? 'finalize and activate' : 'finalize';
 93→        if (!confirm(`Are you sure you want to ${action} this alignment?`)) return;
 94→
 95→        setActionLoading(activate ? 'activate' : 'finalize');
 96→        try {
 97→            await releaseService.finalizeAlignment(alignmentStatus.session.id, activate);
 98→            window.location.href = `/releases/${releaseId}`;
 99→        } catch (err) {
100→            alert(err instanceof Error ? err.message : 'Failed to finalize');
101→            setActionLoading(null);
102→        }
103→    };
104→
105→    const handleCancel = async () => {
106→        if (!alignmentStatus?.session.id) return;
107→
108→        if (!confirm('Are you sure you want to cancel this alignment? The release will return to PREPARATION status.')) return;
109→
110→        setActionLoading('cancel');
111→        try {
112→            await releaseService.cancelAlignment(alignmentStatus.session.id);
113→            window.location.href = `/releases/${releaseId}`;
114→        } catch (err) {
115→            alert(err instanceof Error ? err.message : 'Failed to cancel');
116→            setActionLoading(null);
117→        }
118→    };
119→
120→    const handleDecision = async (reviewId: number, decision: 'ACCEPTED' | 'REJECTED') => {
121→        if (!alignmentStatus?.session.id) return;
122→
123→        setDecisionLoading(reviewId);
124→        try {
125→            await releaseService.submitReviewDecision(
126→                alignmentStatus.session.id,
127→                reviewId,
128→                decision,
129→                decisionComments[reviewId] || undefined
130→            );
131→            setDecisionComments(prev => {
132→                const next = { ...prev };
133→                delete next[reviewId];
134→                return next;
135→            });
136→            loadData();
137→        } catch (err) {
138→            alert(err instanceof Error ? err.message : 'Failed to submit decision');
139→        } finally {
140→            setDecisionLoading(null);
141→        }
142→    };
143→
144→    if (isLoading) {
145→        return (
146→            <div className="d-flex justify-content-center align-items-center py-5">
147→                <div className="spinner-border text-primary" role="status">
148→                    <span className="visually-hidden">Loading...</span>
149→                </div>
150→            </div>
151→        );
152→    }
153→
154→    if (error || !alignmentStatus) {
155→        return (
156→            <div className="alert alert-danger">
157→                <i className="bi bi-exclamation-triangle me-2"></i>
158→                {error || 'No active alignment session found'}
159→            </div>
160→        );
161→    }
162→
163→    const { session, reviewers: reviewerStats, requirements, assessments } = alignmentStatus;
164→    const isOpen = session.status === 'OPEN';
165→
166→    return (
167→        <div className="alignment-dashboard">
168→            {/* Header */}
169→            <div className="d-flex justify-content-between align-items-start mb-4">
170→                <div>
171→                    <h2 className="mb-1">
172→                        <i className="bi bi-clipboard-check me-2 text-primary"></i>
173→                        Alignment Dashboard
174→                    </h2>
175→                    <p className="text-muted mb-0">
176→                        {release?.name} v{release?.version}
177→                    </p>
178→                </div>
179→                <div className="d-flex gap-2">
180→                    <a href={`/releases/${releaseId}`} className="btn btn-outline-secondary">
181→                        <i className="bi bi-arrow-left me-1"></i>
182→                        Back to Release
183→                    </a>
184→                </div>
185→            </div>
186→
187→            {/* Status Banner */}
188→            <div className={`alert ${isOpen ? 'alert-info' : 'alert-secondary'} mb-4`}>
189→                <div className="d-flex justify-content-between align-items-center">
190→                    <div>
191→                        <strong>
192→                            <i className={`bi ${isOpen ? 'bi-hourglass-split' : 'bi-check-circle'} me-2`}></i>
193→                            Status: {session.status}
194→                        </strong>
195→                        <span className="ms-3 text-muted">
196→                            Started {new Date(session.startedAt).toLocaleDateString()}
197→                            {session.completedAt && ` • Completed ${new Date(session.completedAt).toLocaleDateString()}`}
198→                        </span>
199→                    </div>
200→                    {isOpen && canManage && (
201→                        <div className="btn-group">
202→                            <button
203→                                className="btn btn-outline-warning btn-sm"
204→                                onClick={handleSendReminders}
205→                                disabled={actionLoading !== null}
206→                            >
207→                                {actionLoading === 'remind' ? (
208→                                    <span className="spinner-border spinner-border-sm"></span>
209→                                ) : (
210→                                    <><i className="bi bi-bell me-1"></i>Send Reminders</>
211→                                )}
212→                            </button>
213→                        </div>
214→                    )}
215→                </div>
216→            </div>
217→
218→            {/* Stats Cards */}
219→            <div className="row g-3 mb-4">
220→                <div className="col-md-3">
221→                    <div className="card h-100">
222→                        <div className="card-body text-center">
223→                            <h3 className="mb-0 text-primary">{requirements.total}</h3>
224→                            <small className="text-muted">Changed Requirements</small>
225→                        </div>
226→                    </div>
227→                </div>
228→                <div className="col-md-3">
229→                    <div className="card h-100">
230→                        <div className="card-body text-center">
231→                            <h3 className="mb-0">
232→                                {reviewerStats.completed}/{reviewerStats.total}
233→                            </h3>
234→                            <small className="text-muted">Reviewers Complete</small>
235→                            <div className="progress mt-2" style={{ height: '4px' }}>
236→                                <div
237→                                    className="progress-bar bg-success"
238→                                    style={{ width: `${reviewerStats.completionPercent}%` }}
239→                                ></div>
240→                            </div>
241→                        </div>
242→                    </div>
243→                </div>
244→                <div className="col-md-6">
245→                    <div className="card h-100">
246→                        <div className="card-body">
247→                            <div className="d-flex justify-content-around text-center">
248→                                <div>
249→                                    <h4 className="mb-0 text-success">{assessments.ok}</h4>
250→                                    <small className="text-muted">OK</small>
251→                                </div>
252→                                <div>
253→                                    <h4 className="mb-0 text-warning">{assessments.change}</h4>
254→                                    <small className="text-muted">Change</small>
255→                                </div>
256→                                <div>
257→                                    <h4 className="mb-0 text-danger">{assessments.nogo}</h4>
258→                                    <small className="text-muted">NOGO</small>
259→                                </div>
260→                            </div>
261→                        </div>
262→                    </div>
263→                </div>
264→            </div>
265→
266→            {/* Tabs */}
267→            <ul className="nav nav-tabs mb-3">
268→                <li className="nav-item">
269→                    <button
270→                        className={`nav-link ${activeTab === 'overview' ? 'active' : ''}`}
271→                        onClick={() => setActiveTab('overview')}
272→                    >
273→                        Overview
274→                    </button>
275→                </li>
276→                <li className="nav-item">
277→                    <button
278→                        className={`nav-link ${activeTab === 'reviewers' ? 'active' : ''}`}
279→                        onClick={() => setActiveTab('reviewers')}
280→                    >
281→                        Reviewers ({reviewers.length})
282→                    </button>
283→                </li>
284→                <li className="nav-item">
285→                    <button
286→                        className={`nav-link ${activeTab === 'feedback' ? 'active' : ''}`}
287→                        onClick={() => setActiveTab('feedback')}
288→                    >
289→                        Feedback ({feedback.length})
290→                    </button>
291→                </li>
292→            </ul>
293→
294→            {/* Tab Content */}
295→            <div className="tab-content">
296→                {activeTab === 'overview' && (
297→                    <div className="card">
298→                        <div className="card-body">
299→                            <h5 className="card-title">Alignment Overview</h5>
300→                            <dl className="row mb-0">
301→                                <dt className="col-sm-3">Initiated By</dt>
302→                                <dd className="col-sm-9">{session.initiatedBy}</dd>
303→
304→                                <dt className="col-sm-3">Baseline Release</dt>
305→                                <dd className="col-sm-9">
306→                                    {session.baselineReleaseId ? `Release #${session.baselineReleaseId}` : 'None (first release)'}
307→                                </dd>
308→
309→                                <dt className="col-sm-3">Pending Reviewers</dt>
310→                                <dd className="col-sm-9">{reviewerStats.pending}</dd>
311→
312→                                <dt className="col-sm-3">In Progress</dt>
313→                                <dd className="col-sm-9">{reviewerStats.inProgress}</dd>
314→                            </dl>
315→                        </div>
316→                    </div>
317→                )}
318→
319→                {activeTab === 'reviewers' && (
320→                    <div className="card">
321→                        <div className="table-responsive">
322→                            <table className="table table-hover mb-0">
323→                                <thead>
324→                                    <tr>
325→                                        <th>Reviewer</th>
326→                                        <th>Status</th>
327→                                        <th>Progress</th>
328→                                        <th>Assessments</th>
329→                                        <th>Last Activity</th>
330→                                    </tr>
331→                                </thead>
332→                                <tbody>
333→                                    {reviewers.map((reviewer) => (
334→                                        <tr key={reviewer.id}>
335→                                            <td>
336→                                                <strong>{reviewer.username}</strong>
337→                                                <br />
338→                                                <small className="text-muted">{reviewer.email}</small>
339→                                            </td>
340→                                            <td>
341→                                                <span className={`badge bg-${
342→                                                    reviewer.status === 'COMPLETED' ? 'success' :
343→                                                    reviewer.status === 'IN_PROGRESS' ? 'primary' : 'secondary'
344→                                                }`}>
345→                                                    {reviewer.status}
346→                                                </span>
347→                                            </td>
348→                                            <td>
349→                                                <div className="d-flex align-items-center gap-2">
350→                                                    <div className="progress flex-grow-1" style={{ height: '6px', minWidth: '80px' }}>
351→                                                        <div
352→                                                            className="progress-bar"
353→                                                            style={{ width: `${reviewer.completionPercent}%` }}
354→                                                        ></div>
355→                                                    </div>
356→                                                    <small>{reviewer.reviewedCount}/{reviewer.totalCount}</small>
357→                                                </div>
358→                                            </td>
359→                                            <td>
360→                                                <span className="text-success me-2">{reviewer.assessments.ok} OK</span>
361→                                                <span className="text-warning me-2">{reviewer.assessments.change} Change</span>
362→                                                <span className="text-danger">{reviewer.assessments.nogo} NOGO</span>
363→                                            </td>
364→                                            <td>
365→                                                <small className="text-muted">
366→                                                    {reviewer.completedAt
367→                                                        ? `Completed ${new Date(reviewer.completedAt).toLocaleDateString()}`
368→                                                        : reviewer.startedAt
369→                                                        ? `Started ${new Date(reviewer.startedAt).toLocaleDateString()}`
370→                                                        : 'Not started'}
371→                                                </small>
372→                                            </td>
373→                                        </tr>
374→                                    ))}
375→                                </tbody>
376→                            </table>
377→                        </div>
378→                    </div>
379→                )}
380→
381→                {activeTab === 'feedback' && (
382→                    <div className="card">
383→                        <div className="table-responsive">
