  1→/**
  2→ * CrowdStrike Vulnerability Lookup Component
  3→ *
  4→ * Enables real-time querying of CrowdStrike Falcon API for system vulnerabilities
  5→ *
  6→ * Features:
  7→ * - Search form with hostname or AWS instance ID input (Feature 041)
  8→ * - Auto-detection of input type (hostname vs instance ID)
  9→ * - Results table matching CurrentVulnerabilitiesTable design
 10→ * - Filter by severity, exception status, product
 11→ * - Sortable columns
 12→ * - Save to database functionality
 13→ * - Loading and error states
 14→ *
 15→ * Related to:
 16→ * - Feature 015-we-have-currently (CrowdStrike System Vulnerability Lookup)
 17→ * - Feature 041-falcon-instance-lookup (AWS Instance ID Support)
 18→ * Tasks: T031-T036 [US1-Impl], T055-T058 [US3-Impl], T025-T029 [US2-Impl]
 19→ */
 20→
 21→import React, { useState, useEffect, useRef } from 'react';
 22→import {
 23→    queryVulnerabilities,
 24→    saveVulnerabilities,
 25→    type CrowdStrikeQueryResponse,
 26→    type CrowdStrikeVulnerabilityDto
 27→} from '../services/crowdstrikeService';
 28→import {
 29→    formatCacheAge,
 30→    getCacheBadgeVariant,
 31→    getCacheIcon
 32→} from '../utils/cacheUtils';
 33→import { exportVulnerabilitiesToExcel } from '../utils/vulnerabilityExport';
 34→import CveLink from './CveLink';
 35→
 36→/**
 37→ * AWS EC2 Instance ID validation regex
 38→ * Feature: 041-falcon-instance-lookup
 39→ * Task: T027
 40→ *
 41→ * Format: i-[0-9a-fA-F]{8,17}
 42→ */
 43→const AWS_INSTANCE_ID_REGEX = /^i-[0-9a-fA-F]{8,17}$/i;
 44→
 45→/**
 46→ * Check if input matches AWS instance ID pattern
 47→ * Task: T027
 48→ */
 49→const isAwsInstanceId = (input: string): boolean => {
 50→    return AWS_INSTANCE_ID_REGEX.test(input.trim());
 51→};
 52→
 53→const CrowdStrikeVulnerabilityLookup: React.FC = () => {
 54→    // Search state
 55→    const [hostname, setHostname] = useState<string>('');
 56→    const [loading, setLoading] = useState(false);
 57→    const [error, setError] = useState<string | null>(null);
 58→    const [validationError, setValidationError] = useState<string | null>(null);
 59→    const [queryResponse, setQueryResponse] = useState<CrowdStrikeQueryResponse | null>(null);
 60→
 61→    // Filter states
 62→    const [severityFilter, setSeverityFilter] = useState<string>('');
 63→    const [exceptionFilter, setExceptionFilter] = useState<string>('');
 64→    const [productFilter, setProductFilter] = useState<string>('');
 65→
 66→    // Sort states
 67→    const [sortField, setSortField] = useState<string>('detectedAt');
 68→    const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('desc');
 69→
 70→    // Save state
 71→    const [saving, setSaving] = useState(false);
 72→    const [saveSuccess, setSaveSuccess] = useState<string | null>(null);
 73→
 74→    // Export state
 75→    const [exporting, setExporting] = useState(false);
 76→
 77→    // Pagination state
 78→    const [currentPage, setCurrentPage] = useState(0);
 79→    const pageSize = 100;
 80→
 81→    // Track if initial search from URL param has been triggered
 82→    const initialSearchDone = useRef(false);
 83→
 84→    /**
 85→     * Check for hostname in URL parameters and auto-search on mount
 86→     * This enables deep-linking from other views (e.g., Domain Vulnerabilities)
 87→     */
 88→    useEffect(() => {
 89→        // Only run once on mount
 90→        if (initialSearchDone.current) return;
 91→
 92→        const urlParams = new URLSearchParams(window.location.search);
 93→        const hostnameParam = urlParams.get('hostname');
 94→
 95→        if (hostnameParam) {
 96→            console.log('[CrowdStrikeVulnerabilityLookup] Found hostname in URL:', hostnameParam);
 97→            initialSearchDone.current = true;
 98→            setHostname(hostnameParam);
 99→
100→            // Clean the URL to prevent re-search on refresh
101→            window.history.replaceState({}, '', '/vulnerabilities/system');
102→
103→            // Trigger search after state is set
104→            // Use a small timeout to ensure state is updated
105→            setTimeout(async () => {
106→                setLoading(true);
107→                setError(null);
108→                setValidationError(null);
109→                setQueryResponse(null);
110→
111→                try {
112→                    const response = await queryVulnerabilities(hostnameParam.trim(), false, 0, pageSize);
113→                    console.log('[CrowdStrikeVulnerabilityLookup] Auto-search successful:', response);
114→                    setQueryResponse(response);
115→                } catch (err) {
116→                    console.error('[CrowdStrikeVulnerabilityLookup] Auto-search failed:', err);
117→                    setError(err instanceof Error ? err.message : 'Failed to query CrowdStrike');
118→                } finally {
119→                    setLoading(false);
120→                }
121→            }, 0);
122→        }
123→    }, []);
124→
125→    /**
126→     * Handle input change with validation
127→     * Feature: 041-falcon-instance-lookup
128→     * Task: T027, T028, T029
129→     */
130→    const handleInputChange = (value: string) => {
131→        setHostname(value);
132→        setValidationError(null); // Clear validation error when user types (T029)
133→        setError(null); // Clear general error
134→    };
135→
136→    /**
137→     * Validate input before search
138→     * Feature: 041-falcon-instance-lookup
139→     * Task: T027, T028
140→     */
141→    const validateInput = (input: string): boolean => {
142→        const trimmed = input.trim();
143→
144→        if (!trimmed) {
145→            setValidationError('Please enter a hostname or instance ID');
146→            return false;
147→        }
148→
149→        // If it looks like an instance ID, validate the format
150→        if (trimmed.startsWith('i-')) {
151→            if (!isAwsInstanceId(trimmed)) {
152→                setValidationError(
153→                    "Invalid instance ID format. Expected 'i-' followed by 8 or 17 hexadecimal characters (e.g., i-0068f94221fe120df)"
154→                );
155→                return false;
156→            }
157→        }
158→
159→        return true;
160→    };
161→
162→    /**
163→     * Handle search form submission
164→     * Feature: 041-falcon-instance-lookup
165→     * Tasks: T033 [US1-Impl], T027, T028 [US2-Impl], T039 [US3-Impl]
166→     *
167→     * @param e Form event (optional)
168→     * @param forceRefresh If true, bypass cache (Feature 041, Task T039)
169→     */
170→    const handleSearch = async (e?: React.FormEvent, forceRefresh: boolean = false, page: number = 0) => {
171→        if (e) e.preventDefault();
172→
173→        // Validate input (T027, T028)
174→        if (!validateInput(hostname)) {
175→            return;
176→        }
177→
178→        const trimmedInput = hostname.trim();
179→        const inputType = isAwsInstanceId(trimmedInput) ? 'instance ID' : 'hostname';
180→
181→        console.log(`[CrowdStrikeVulnerabilityLookup] handleSearch called: ${inputType} = ${trimmedInput}, force = ${forceRefresh}, page = ${page}`);
182→        setLoading(true);
183→        setError(null);
184→        setValidationError(null);
185→        setQueryResponse(null);
186→        setSaveSuccess(null);
187→
188→        try {
189→            const response = await queryVulnerabilities(trimmedInput, forceRefresh, page, pageSize);
190→            console.log('[CrowdStrikeVulnerabilityLookup] Query successful:', response);
191→            setQueryResponse(response);
192→            setCurrentPage(page);
193→            setError(null);
194→            setValidationError(null);
195→        } catch (err) {
196→            console.error('[CrowdStrikeVulnerabilityLookup] Query failed:', err);
197→            setError(err instanceof Error ? err.message : 'Failed to query CrowdStrike');
198→            setQueryResponse(null);
199→        } finally {
200→            setLoading(false);
201→        }
202→    };
203→
204→    /**
205→     * Handle refresh button click with cache bypass
206→     * Feature: 041-falcon-instance-lookup
207→     * Task: T039 [US3-Impl]
208→     */
209→    const handleRefresh = () => {
210→        console.log('[CrowdStrikeVulnerabilityLookup] handleRefresh called with force=true');
211→        handleSearch(undefined, true, currentPage); // T039: Pass force=true to bypass cache
212→    };
213→
214→    /**
215→     * Handle page change for pagination
216→     */
217→    const handlePageChange = (newPage: number) => {
218→        console.log('[CrowdStrikeVulnerabilityLookup] handlePageChange called:', newPage);
219→        handleSearch(undefined, false, newPage);
220→    };
221→
222→    /**
223→     * Handle save to database
224→     * Feature: 041-falcon-instance-lookup
225→     * Task: T057 [US3-Impl], T050 [US4-Impl]
226→     */
227→    const handleSave = async () => {
228→        const vulnerabilities = queryResponse?.vulnerabilities ?? [];
229→        if (!queryResponse || vulnerabilities.length === 0) {
230→            setError('No vulnerabilities to save');
231→            return;
232→        }
233→
234→        console.log('[CrowdStrikeVulnerabilityLookup] handleSave called');
235→        setSaving(true);
236→        setError(null);
237→        setSaveSuccess(null);
238→
239→        try {
240→            // T050: Include instanceId in save request (Feature 041)
241→            const response = await saveVulnerabilities({
242→                hostname: queryResponse.hostname,
243→                vulnerabilities: vulnerabilities,
244→                instanceId: queryResponse.instanceId || undefined
245→            });
246→            console.log('[CrowdStrikeVulnerabilityLookup] Save successful:', response);
247→
248→            // T014, T051: Update success message to show saved, skipped, created counts, and instance ID
249→            const parts = [];
250→            if (response.vulnerabilitiesSaved > 0) {
251→                parts.push(`${response.vulnerabilitiesSaved} vulnerabilities saved`);
252→            }
253→            if (response.vulnerabilitiesSkipped > 0) {
254→                parts.push(`${response.vulnerabilitiesSkipped} skipped`);
255→            }
256→            if (response.assetsCreated > 0) {
257→                parts.push(`${response.assetsCreated} asset created`);
258→            }
