370→                aVal = severityOrder[a.severity as keyof typeof severityOrder] || 0;
371→                bVal = severityOrder[b.severity as keyof typeof severityOrder] || 0;
372→            } else if (sortField === 'daysOpen') {
373→                // Parse "X days" string to number
