381→                bVal = (b as any)[sortField];
382→            }
383→
384→            if (aVal === null || aVal === undefined) return 1;
385→            if (bVal === null || bVal === undefined) return -1;
386→
387→            const comparison = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
388→            return sortOrder === 'asc' ? comparison : -comparison;
