 46→ * Check if input matches AWS instance ID pattern
 47→ * Task: T027
 48→ */
 49→const isAwsInstanceId = (input: string): boolean => {
 50→    return AWS_INSTANCE_ID_REGEX.test(input.trim());
 51→};
