 53→const CrowdStrikeVulnerabilityLookup: React.FC = () => {
 54→    // Search state
 55→    const [hostname, setHostname] = useState<string>('');
 56→    const [loading, setLoading] = useState(false);
 57→    const [error, setError] = useState<string | null>(null);
 58→    const [validationError, setValidationError] = useState<string | null>(null);
 59→    const [queryResponse, setQueryResponse] = useState<CrowdStrikeQueryResponse | null>(null);
 60→
 61→    // Filter states
