  1→/**
  2→ * CrowdStrike Service
  3→ *
  4→ * Handles API calls for CrowdStrike Falcon vulnerability lookup functionality
  5→ *
  6→ * Related to: Feature 015-we-have-currently (CrowdStrike System Vulnerability Lookup)
  7→ * Tasks: T029-T030 [US1-Impl], T052-T054 [US3-Impl]
  8→ */
  9→
 10→/**
 11→ * CrowdStrike Vulnerability DTO
 12→ * Matches backend CrowdStrikeVulnerabilityDto
 13→ */
 14→export interface CrowdStrikeVulnerabilityDto {
 15→    id: string;
 16→    hostname: string;
 17→    ip: string | null;
 18→    cveId: string | null;
 19→    severity: string;
 20→    cvssScore: number | null;
 21→    affectedProduct: string | null;
 22→    daysOpen: string | null;
 23→    detectedAt: string;
 24→    status: string;
 25→    hasException: boolean;
 26→    exceptionReason: string | null;
 27→}
 28→
 29→/**
 30→ * Query Response
 31→ * Matches backend CrowdStrikeQueryResponse
 32→ * Feature: 041-falcon-instance-lookup
 33→ */
 34→export interface CrowdStrikeQueryResponse {
 35→    hostname: string;
 36→    instanceId?: string | null;
 37→    deviceCount?: number | null;
 38→    cloudAccountId?: string | null;
 39→    vulnerabilities: CrowdStrikeVulnerabilityDto[];
 40→    totalCount: number;
 41→    queriedAt: string;
 42→}
 43→
 44→/**
 45→ * Save Request
 46→ * Matches backend CrowdStrikeSaveRequest
 47→ * Feature: 041-falcon-instance-lookup
 48→ */
 49→export interface CrowdStrikeSaveRequest {
 50→    hostname: string;
 51→    vulnerabilities: CrowdStrikeVulnerabilityDto[];
 52→    instanceId?: string; // T050: Optional instance ID for asset enrichment
 53→}
 54→
 55→/**
 56→ * Save Response
 57→ * Matches backend CrowdStrikeSaveResponse
 58→ * Feature 030 - CrowdStrike Asset Auto-Creation
 59→ * Feature 043 - CrowdStrike Domain Import (added domain statistics)
 60→ */
 61→export interface CrowdStrikeSaveResponse {
 62→    message: string;
 63→    vulnerabilitiesSaved: number;
 64→    vulnerabilitiesSkipped: number;  // Feature 030: Added for T014
 65→    assetsCreated: number;
 66→    uniqueDomainCount?: number;  // Feature 043: Number of unique domains discovered
 67→    discoveredDomains?: string[];  // Feature 043: List of unique domain names
 68→    errors: string[];
 69→}
 70→
 71→/**
 72→ * Query CrowdStrike for system vulnerabilities
 73→ *
 74→ * Feature: 041-falcon-instance-lookup
 75→ * Task: T030 [US1-Impl], T036 [US3-Impl]
 76→ *
 77→ * @param hostname System hostname or AWS instance ID to query
 78→ * @param force If true, bypass cache and fetch fresh data (Feature 041, Task T035)
 79→ * @returns Query response with vulnerabilities
 80→ * @throws Error if authentication fails, hostname not found, rate limit exceeded, or API error
 81→ */
 82→export async function queryVulnerabilities(
 83→    hostname: string,
 84→    force: boolean = false,
 85→    page: number = 0,
 86→    limit: number = 100
 87→): Promise<CrowdStrikeQueryResponse> {
 88→    console.log('[CrowdStrikeService] queryVulnerabilities called');
 89→    console.log('[CrowdStrikeService] Hostname:', hostname);
 90→    console.log('[CrowdStrikeService] Force refresh:', force);
 91→    console.log('[CrowdStrikeService] Page:', page, 'Limit:', limit);
 92→
 93→    // Use new endpoint that supports both hostname and instance ID (Feature 041)
 94→    const forceParam = force ? '&force=true' : '';
 95→    const pageParam = `&page=${page}&limit=${limit}`;
 96→    const url = `/api/vulnerabilities?hostname=${encodeURIComponent(hostname)}${forceParam}${pageParam}`;
 97→    console.log('[CrowdStrikeService] Calling API:', url);
 98→
 99→    try {
100→        const response = await fetch(url, {
101→            method: 'GET',
102→            headers: {
103→                'Content-Type': 'application/json'
104→            },
105→            credentials: 'include'  // Send HttpOnly cookie for authentication
106→        });
107→
108→        console.log('[CrowdStrikeService] Response status:', response.status);
109→        console.log('[CrowdStrikeService] Response ok:', response.ok);
110→
111→        // Handle specific error cases
112→        if (!response.ok) {
113→            // Handle specific HTTP status codes first (before trying to parse body)
114→            if (response.status === 401) {
115→                window.location.href = '/login';
116→                throw new Error('Session expired. Please log in again.');
117→            } else if (response.status === 403) {
118→                throw new Error('Insufficient permissions. ADMIN or VULN role required.');
119→            } else if (response.status === 404) {
120→                const isInstanceId = hostname.trim().toLowerCase().startsWith('i-');
121→                const identifier = isInstanceId ? 'instance ID' : 'hostname';
122→                throw new Error(`System not found with ${identifier}: ${hostname}`);
123→            } else if (response.status === 429) {
124→                const retryAfter = response.headers.get('Retry-After') || '30';
125→                throw new Error(`Rate limit exceeded. Try again in ${retryAfter} seconds.`);
126→            }
127→
128→            // Try to parse error response as JSON
129→            const contentType = response.headers.get('content-type');
130→            if (contentType && contentType.includes('application/json')) {
131→                try {
132→                    const errorData = await response.json();
133→                    console.error('[CrowdStrikeService] Error response:', errorData);
134→                    const errorMessage = errorData.error || errorData.message || `Query failed with status ${response.status}`;
135→                    throw new Error(errorMessage);
136→                } catch (e) {
137→                    if (e instanceof Error && !e.message.includes('Query failed')) {
138→                        throw e;
139→                    }
140→                    console.error('[CrowdStrikeService] Failed to parse JSON error:', e);
141→                }
142→            } else {
143→                // Non-JSON response (likely HTML error page)
144→                const text = await response.text();
145→                console.error('[CrowdStrikeService] Non-JSON error response:', text.substring(0, 200));
146→
147→                // Extract meaningful error from HTML if possible
148→                if (response.status === 500 || response.status === 502 || response.status === 503) {
149→                    throw new Error('CrowdStrike API error: Server temporarily unavailable. Please try again.');
150→                } else if (response.status === 504) {
151→                    throw new Error('CrowdStrike API error: Request timed out. The system may have too many vulnerabilities. Please try again.');
152→                }
153→            }
154→
155→            throw new Error(`CrowdStrike API error: Failed to query Spotlight API: Read Timeout`);
156→        }
157→
158→        // Parse successful response
159→        const contentType = response.headers.get('content-type');
160→        if (!contentType || !contentType.includes('application/json')) {
161→            const text = await response.text();
162→            console.error('[CrowdStrikeService] Unexpected non-JSON success response:', text.substring(0, 200));
163→            throw new Error('Unexpected response format from server');
164→        }
165→
166→        const result = await response.json();
167→        console.log('[CrowdStrikeService] Success response:', result);
