176→/**
177→ * Save CrowdStrike vulnerabilities to database
178→ *
179→ * Task: T054 [US3-Impl]
180→ *
181→ * @param request Save request with hostname and vulnerabilities
182→ * @returns Save response with results
183→ * @throws Error if authentication fails, validation fails, or database error
184→ */
185→export async function saveVulnerabilities(
186→    request: CrowdStrikeSaveRequest
187→): Promise<CrowdStrikeSaveResponse> {
188→    console.log('[CrowdStrikeService] saveVulnerabilities called');
189→    console.log('[CrowdStrikeService] Hostname:', request.hostname);
190→    console.log('[CrowdStrikeService] Vulnerabilities count:', request.vulnerabilities.length);
191→
192→    const url = '/api/crowdstrike/vulnerabilities/save';
193→    console.log('[CrowdStrikeService] Calling API:', url);
194→
195→    try {
196→        const response = await fetch(url, {
197→            method: 'POST',
198→            headers: {
199→                'Content-Type': 'application/json'
200→            },
201→            credentials: 'include',  // Send HttpOnly cookie for authentication
202→            body: JSON.stringify(request)
203→        });
204→
205→        console.log('[CrowdStrikeService] Response status:', response.status);
206→        console.log('[CrowdStrikeService] Response ok:', response.ok);
207→
208→        if (!response.ok) {
209→            // Handle specific HTTP status codes first
210→            if (response.status === 401) {
211→                window.location.href = '/login';
212→                throw new Error('Session expired. Please log in again.');
213→            } else if (response.status === 403) {
214→                throw new Error('Insufficient permissions. ADMIN or VULN role required.');
215→            }
216→
217→            // Try to parse error response as JSON
218→            const contentType = response.headers.get('content-type');
219→            if (contentType && contentType.includes('application/json')) {
220→                try {
221→                    const errorData = await response.json();
222→                    console.error('[CrowdStrikeService] Error response:', errorData);
223→                    const errorMessage = errorData.error || errorData.message || `Save failed with status ${response.status}`;
224→
225→                    if (response.status === 400) {
226→                        throw new Error(`Validation error: ${errorMessage}`);
227→                    }
228→                    throw new Error(errorMessage);
229→                } catch (e) {
230→                    if (e instanceof Error && !e.message.includes('Save failed')) {
231→                        throw e;
232→                    }
233→                    console.error('[CrowdStrikeService] Failed to parse JSON error:', e);
234→                }
235→            } else {
236→                // Non-JSON response (likely HTML error page)
237→                const text = await response.text();
238→                console.error('[CrowdStrikeService] Non-JSON error response:', text.substring(0, 200));
239→            }
240→
241→            throw new Error(`Save failed with status ${response.status}`);
242→        }
243→
244→        // Parse successful response
245→        const contentType = response.headers.get('content-type');
246→        if (!contentType || !contentType.includes('application/json')) {
247→            const text = await response.text();
248→            console.error('[CrowdStrikeService] Unexpected non-JSON success response:', text.substring(0, 200));
249→            throw new Error('Unexpected response format from server');
250→        }
251→
252→        const result = await response.json();
253→        console.log('[CrowdStrikeService] Success response:', result);
254→        console.log('[CrowdStrikeService] Vulnerabilities saved:', result.vulnerabilitiesSaved);
255→        console.log('[CrowdStrikeService] Assets created:', result.assetsCreated);
256→        return result;
257→    } catch (error) {
258→        console.error('[CrowdStrikeService] Fetch error:', error);
259→        throw error;
260→    }
261→}
