361→    const getFilteredVulnerabilities = (): CrowdStrikeVulnerabilityDto[] => {
362→        if (!queryResponse) return [];
363→
364→        // Handle case where vulnerabilities is undefined/null (e.g., when totalCount is 0)
365→        const vulnerabilities = queryResponse.vulnerabilities ?? [];
366→
367→        return vulnerabilities.filter(vuln => {
368→            // Severity filter
369→            if (severityFilter && vuln.severity !== severityFilter) return false;
370→
371→            // Exception filter
372→            if (exceptionFilter === 'EXCEPTED' && !vuln.hasException) return false;
373→            if (exceptionFilter === 'NOT_EXCEPTED' && vuln.hasException) return false;
374→
375→            // Product filter
376→            if (productFilter && !vuln.affectedProduct?.toLowerCase().includes(productFilter.toLowerCase())) {
377→                return false;
378→            }
379→
380→            return true;
381→        });
