384→    /**
385→     * Get sorted vulnerabilities
386→     * Task: T043 [US2-Impl]
387→     */
388→    const getSortedVulnerabilities = (filtered: CrowdStrikeVulnerabilityDto[]): CrowdStrikeVulnerabilityDto[] => {
389→        return [...filtered].sort((a, b) => {
390→            let aVal: any;
391→            let bVal: any;
392→
393→            // Handle sorting for different field types
394→            if (sortField === 'severity') {
395→                // Custom severity order
396→                const severityOrder = { 'Critical': 4, 'High': 3, 'Medium': 2, 'Low': 1, 'Informational': 0 };
397→                aVal = severityOrder[a.severity as keyof typeof severityOrder] || 0;
398→                bVal = severityOrder[b.severity as keyof typeof severityOrder] || 0;
399→            } else if (sortField === 'daysOpen') {
400→                // Parse "X days" string to number
401→                aVal = parseInt(a.daysOpen?.split(' ')[0] || '0');
402→                bVal = parseInt(b.daysOpen?.split(' ')[0] || '0');
403→            } else if (sortField === 'detectedAt') {
404→                aVal = new Date(a.detectedAt).getTime();
405→                bVal = new Date(b.detectedAt).getTime();
406→            } else {
407→                aVal = (a as any)[sortField];
408→                bVal = (b as any)[sortField];
409→            }
410→
411→            if (aVal === null || aVal === undefined) return 1;
412→            if (bVal === null || bVal === undefined) return -1;
413→
414→            const comparison = aVal < bVal ? -1 : aVal > bVal ? 1 : 0;
415→            return sortOrder === 'asc' ? comparison : -comparison;
416→        });
417→    };
