445→    /**
446→     * Get exception badge
447→     * Task: T036 [US1-Impl]
448→     * Shows "N/A" when vulnerability is not yet overdue (< 30 days)
449→     */
450→    const getExceptionBadge = (hasException: boolean, reason: string | null, daysOpen: string | null) => {
451→        if (hasException) {
452→            return (
453→                <span
454→                    className="badge bg-success"
455→                    title={reason || "This vulnerability is excepted"}
456→                >
457→                    Excepted
458→                </span>
459→            );
460→        }
461→
462→        // Parse days from string like "7 days"
463→        const days = parseInt(daysOpen?.split(' ')[0] || '0');
464→
465→        // If under 30 days, exception not needed yet
466→        if (days < 30) {
467→            return <span className="badge bg-secondary" title="Exception not required yet (under 30 days)">N/A</span>;
468→        }
469→
470→        return <span className="badge bg-danger" title="No active exception">Not Excepted</span>;
471→    };
