@Get("/vulnerabilities")
open fun queryVulnerabilities(
    @QueryValue hostname: String?,
    @QueryValue severity: String? = null,
    @QueryValue product: String? = null,
    @QueryValue limit: Int? = null,
    @QueryValue page: Int? = null,
    @QueryValue(defaultValue = "false") force: Boolean = false
): HttpResponse<*> {
    log.info(
        "Received vulnerability query: input={}, severity={}, product={}, limit={}, page={}, force={}",
        hostname, severity, product, limit, page, force
    )

    return try {
        // Validate hostname is not null or blank
        if (hostname.isNullOrBlank()) {
            throw IllegalArgumentException("Hostname or instance ID is required")
        }

        val trimmedInput = hostname.trim()

        // Validate limit
        val pageSize = when {
            limit == null -> 100
            limit < 1 -> {
                throw IllegalArgumentException("Limit must be greater than 0")
            }
            limit > 1000 -> {
                throw IllegalArgumentException("Limit cannot exceed 1000")
            }
            else -> limit
        }

        val pageNumber = when {
            page == null -> 0
            page < 0 -> {
                throw IllegalArgumentException("Page must be 0 or greater")
            }
            else -> page
        }

        // T035: If force=true, invalidate cache before querying
        if (force) {
            log.info("Force refresh requested - invalidating cache for input: {}", trimmedInput)
            if (InputDetectionUtils.isAwsInstanceId(trimmedInput)) {
                val normalizedInstanceId = ValidationUtils.validateAndNormalizeAwsInstanceId(trimmedInput)
                invalidateCacheForInstanceId(normalizedInstanceId, severity, product, pageSize)
            } else {
                val sanitizedHostname = sanitizeHostname(trimmedInput)
                invalidateCacheForHostname(sanitizedHostname, severity, product, pageSize)
            }
        }

        // Detect query type and route to appropriate service method
        val response: CrowdStrikeQueryResponse = if (InputDetectionUtils.isAwsInstanceId(trimmedInput)) {
            // Instance ID query (Feature 041)
            // T017: Validate instance ID format
            try {
                val normalizedInstanceId = ValidationUtils.validateAndNormalizeAwsInstanceId(trimmedInput)
                log.info("Detected AWS instance ID query: instanceId={}", normalizedInstanceId)

                queryService.queryByInstanceId(
                    instanceId = normalizedInstanceId,
                    severity = severity,
                    product = product,
                    limit = pageSize,
                    page = pageNumber
                )
            } catch (e: IllegalArgumentException) {
                // T017: Clear error message for invalid instance ID format
                throw IllegalArgumentException(ValidationUtils.getInstanceIdValidationError(trimmedInput))
            }
        } else {
            // Hostname query (existing functionality)
            val sanitizedHostname = sanitizeHostname(trimmedInput)
            log.info("Detected hostname query: hostname={}", sanitizedHostname)

            queryService.queryVulnerabilities(
                hostname = sanitizedHostname,
                severity = severity,
                product = product,
                limit = pageSize,
                page = pageNumber
            )
        }

        log.info(
            "Query successful: input={}, severity={}, product={}, found={}",
            trimmedInput, severity, product, response.vulnerabilities.size

@Cacheable("vulnerability_queries")
open fun queryVulnerabilities(
    hostname: String,
    severity: String? = null,
    product: String? = null,
    limit: Int = 100,
    page: Int = 0
): CrowdStrikeQueryResponse {
    require(hostname.isNotBlank()) { "Hostname cannot be blank" }

    log.info(
        "Querying vulnerabilities: hostname={}, severity={}, product={}, limit={}, page={}",
        hostname, severity, product, limit, page
    )

    // Check database first - if vulnerabilities exist locally, serve them
    val dbResponse = queryFromDatabaseByHostname(hostname, limit, page)
    if (dbResponse != null) {
        log.info(
            "Serving vulnerabilities from database: hostname={}, found={}",
            hostname, dbResponse.vulnerabilities.size
        )
        return applyFilters(dbResponse, severity, product)
    }

    // Fall through to CrowdStrike API
    try {
        // Get config from database
        val config = getConfiguration()

        // Query API (returns shared module's CrowdStrikeQueryResponse)
        val sharedResponse = apiClient.queryAllVulnerabilities(hostname, config, limit)

        // Convert shared response to backend response, then apply filters
        val backendResponse = sharedResponse.toBackendResponse()
        val filtered = applyFilters(backendResponse, severity, product)

        log.info(
            "Query successful: hostname={}, found={}, filtered={}",
            hostname, sharedResponse.vulnerabilities.size, filtered.vulnerabilities.size
        )

        return filtered
    } catch (e: NotFoundException) {
        log.warn("Hostname not found: {}", hostname)
        throw CrowdStrikeError.NotFoundError(
            hostname = hostname,
            cause = e
        )
    } catch (e: RateLimitException) {
        log.warn("Rate limit exceeded: {}", e.message)
        throw CrowdStrikeError.RateLimitError(
            retryAfterSeconds = 60,
            cause = e
        )
    } catch (e: CrowdStrikeException) {
        log.error("CrowdStrike API error: {}", e.message, e)
        throw CrowdStrikeError.ServerError(
            message = "CrowdStrike API error: ${e.message}",
            cause = e
        )
    } catch (e: CrowdStrikeError) {
        // Re-throw internal errors
        throw e
    } catch (e: Exception) {
        log.error("Unexpected error querying CrowdStrike", e)
        throw CrowdStrikeError.ServerError(
            message = "Unexpected error: ${e.message}",
            cause = e
        )
    }
}

